## Session
```typescript
// Express + express-session + Redis
import session from "express-session";
import RedisStore from "connect-redis";

app.use(session({
  store: new RedisStore({ client: redis }),
  secret: process.env.SESSION_SECRET,
  cookie: {
    httpOnly: true,
    secure: true,
    sameSite: "lax",
    maxAge: 24 * 60 * 60 * 1000  // 1 天
  }
}));

// 登入
app.post("/login", async (req, res) => {
  const user = await validateUser(req.body);
  req.session.userId = user.id;
  res.json({ user });
});

// 中介
function requireAuth(req, res, next) {
  if (!req.session.userId) return res.status(401).end();
  next();
}
```

## JWT
```typescript
import { SignJWT, jwtVerify } from "jose";

const secret = new TextEncoder().encode(process.env.JWT_SECRET);

// 簽
async function signToken(payload) {
  return await new SignJWT(payload)
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("15m")
    .sign(secret);
}

// 驗
async function verifyToken(token) {
  const { payload } = await jwtVerify(token, secret);
  return payload;
}

// 登入回 access + refresh
app.post("/login", async (req, res) => {
  const user = await validateUser(req.body);
  const accessToken = await signToken({ sub: user.id });
  const refreshToken = crypto.randomBytes(32).toString("hex");

  // 存 refresh token 在 DB（可 revoke）
  await db.refreshTokens.create({
    data: { token: refreshToken, userId: user.id, expiresAt: new Date(Date.now() + 30 * 86400000) }
  });

  res.cookie("refresh", refreshToken, { httpOnly: true, secure: true });
  res.json({ accessToken });
});

// Refresh
app.post("/refresh", async (req, res) => {
  const refresh = req.cookies.refresh;
  const record = await db.refreshTokens.findUnique({ where: { token: refresh } });
  if (!record || record.expiresAt < new Date()) {
    return res.status(401).end();
  }
  const accessToken = await signToken({ sub: record.userId });
  res.json({ accessToken });
});
```

## Cookie vs LocalStorage
- **Cookie HttpOnly**：JS 讀不到、防 XSS
- **localStorage**：JS 讀得到、XSS 偷得到

永遠 cookie（HttpOnly + Secure + SameSite）。

## Refresh Token Rotation
每次 refresh 換新的 refresh token：
```typescript
// Refresh
const newRefresh = crypto.randomBytes(32).toString("hex");
await db.refreshTokens.update({
  where: { token: oldRefresh },
  data: { token: newRefresh, expiresAt: ... }
});
```

舊的被用 = 知道有人偷 → revoke 全部。

## Logout
```typescript
// Session
req.session.destroy();

// JWT
await db.refreshTokens.delete({ where: { token: refresh } });
res.clearCookie("refresh");
```

## 心法
- Cookie HttpOnly（防 XSS）
- Short access + long refresh
- Refresh rotation
- Logout revoke refresh

**☕ 用人話講**

Session vs JWT 實作——**兩種主流的 token 管理方式**對比。**一句話記住**：Session 像寄物櫃號碼牌（東西在櫃台、你只拿牌子）、JWT 像隨身證件（資訊都在你身上帶著）；前者好撤銷、後者免查庫、各有取捨。

